+function openInBrowser(url: string) {
+  const args =
+    process.platform === 'darwin'
+      ? ['open', url]
+      : process.platform === 'win32'
+        ? ['cmd', '/c', 'start', '', url]
+        : ['xdg-open', url]
+  const child = spawn(args[0]!, args.slice(1), { stdio: 'ignore', detached: true })
+  child.unref()
+}
